<script>
// import Serve from "../service/serve";
import pdf from "pdfvuer";

export default {
  data() {
    return {
      pageNumber: 1,
    };
  },
  computed: {},
  methods: {
    increasePage() {
      if (this.pageNumber + 1 < 3) {
        this.pageNumber++;
      }
    },
    decreasePage() {
      if (this.pageNumber - 1 > 0) {
        this.pageNumber--;
      }
    },
  },
  components: {
    pdf,
  },
};
</script>

